/// Executor for ShareCreation flow
pub struct ShareCreationFlowExecutor<H: ShareCreationStepHandler> {
    handler: Arc<H>,
}

impl<H: ShareCreationStepHandler> ShareCreationFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<ShareCreationFlowInstance, FlowError> {
        let mut instance = ShareCreationFlowInstance::new(instance_id);
        instance.status = ShareCreationFlowStatus::Running;
        instance.current_step = Some(ShareCreationFlowStep::ValidateFile);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut ShareCreationFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            ShareCreationFlowStep::ValidateFile => {
                self.handler.handle_validate_file(instance).await?
            }
            ShareCreationFlowStep::CheckSharePermission => {
                let next = self.handler.evaluate_check_share_permission(instance).await?;
                Some(next)
            }
            ShareCreationFlowStep::CheckManagePermission => {
                self.handler.handle_check_manage_permission(instance).await?
            }
            ShareCreationFlowStep::CheckShareType => {
                let next = self.handler.evaluate_check_share_type(instance).await?;
                Some(next)
            }
            ShareCreationFlowStep::ValidatePublicShare => {
                self.handler.handle_validate_public_share(instance).await?
            }
            ShareCreationFlowStep::ValidateUserShare => {
                self.handler.handle_validate_user_share(instance).await?
            }
            ShareCreationFlowStep::ValidateEmailShare => {
                self.handler.handle_validate_email_share(instance).await?
            }
            ShareCreationFlowStep::CheckExistingShare => {
                self.handler.handle_check_existing_share(instance).await?
            }
            ShareCreationFlowStep::UpdateExistingShare => {
                self.handler.handle_update_existing_share(instance).await?
            }
            ShareCreationFlowStep::CreateShareRecord => {
                self.handler.handle_create_share_record(instance).await?
            }
            ShareCreationFlowStep::GenerateShareUrl => {
                self.handler.handle_generate_share_url(instance).await?
            }
            ShareCreationFlowStep::DetermineNotification => {
                let next = self.handler.evaluate_determine_notification(instance).await?;
                Some(next)
            }
            ShareCreationFlowStep::NotifyUser => {
                self.handler.handle_notify_user(instance).await?
            }
            ShareCreationFlowStep::SendEmailInvitation => {
                self.handler.handle_send_email_invitation(instance).await?
            }
            ShareCreationFlowStep::LogShare => {
                self.handler.handle_log_share(instance).await?
            }
            ShareCreationFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::FileNotFound => {
                self.handler.handle_file_not_found(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::PermissionDenied => {
                self.handler.handle_permission_denied(instance).await?
            }
            ShareCreationFlowStep::FailedPermission => {
                self.handler.handle_failed_permission(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::PublicSharingDisabled => {
                self.handler.handle_public_sharing_disabled(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::UserNotFound => {
                self.handler.handle_user_not_found(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::InvalidConfig => {
                self.handler.handle_invalid_config(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = ShareCreationFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut ShareCreationFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != ShareCreationFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut ShareCreationFlowInstance) {
        instance.status = ShareCreationFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut ShareCreationFlowInstance, error: impl Into<String>) {
        instance.status = ShareCreationFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = ShareCreationFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, ShareCreationFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = ShareCreationFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = ShareCreationFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = ShareCreationFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = ShareCreationFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}